const SPONSORED_POST_SRC = "// src/components/SponsoredPost.jsx\n// Annonce affich\u00e9e comme une PUBLICATION dans le fil (photo ou vid\u00e9o).\n// Les annonces proviennent de la collection Firestore \"ads\" (active == true).\n// Si aucune annonce active \u2192 une \"house ad\" Trengo s'affiche (auto-promo).\nimport { useState, useEffect } from 'react';\nimport {\n  collection, query, where, limit, onSnapshot, doc, updateDoc, increment,\n} from 'firebase/firestore';\nimport { db } from '../firebase';\n\nconst HOUSE_AD = {\n  id: '__house__',\n  sponsor: 'Trengo',\n  logo: '/trengo-logo.png',\n  text: 'Trengo \u2014 ny tambajotra sosialy malagasy \ud83c\uddf2\ud83c\uddec. Zarao, mifandraisa, mifankahalala.',\n  mediaType: 'image',\n  mediaURL: '/trengo-icon-512.png',\n  link: 'https://trengo-mg.vercel.app',\n  cta: 'Hitsidika',\n};\n\n// Hook : charge les annonces actives (temps r\u00e9el). Fallback \u2192 house ad.\nexport function useFeedAds() {\n  const [ads, setAds] = useState([]);\n  useEffect(() => {\n    let unsub = () => {};\n    try {\n      const q = query(collection(db, 'ads'), where('active', '==', true), limit(20));\n      unsub = onSnapshot(\n        q,\n        (snap) => {\n          const list = snap.docs.map((d) => ({ id: d.id, ...d.data() }));\n          setAds(list.length ? list : [HOUSE_AD]);\n        },\n        () => setAds([HOUSE_AD])\n      );\n    } catch (e) {\n      setAds([HOUSE_AD]);\n    }\n    return () => unsub();\n  }, []);\n  return ads;\n}\n\nfunction trackClick(ad) {\n  if (!ad || ad.id === '__house__') return;\n  try { updateDoc(doc(db, 'ads', ad.id), { clicks: increment(1) }); } catch (e) {}\n}\n\nexport default function SponsoredPost({ ad }) {\n  if (!ad) return null;\n  const open = () => {\n    trackClick(ad);\n    if (ad.link) window.open(ad.link, '_blank', 'noopener');\n  };\n  return (\n    <div className=\"card post-card animate-fade\" style={{ marginBottom: 14, border: '1px solid #a855f733' }}>\n      <div style={{ background: 'linear-gradient(135deg,#7c3aed18,#a855f718)', borderBottom: '1px solid #a855f733', padding: '5px 14px' }}>\n        <span style={{ fontSize: 10, color: '#a855f7', fontWeight: 600 }}>\u26a1 Sponsoris\u00e9</span>\n      </div>\n\n      <div style={{ padding: '12px 16px 0', display: 'flex', alignItems: 'center', gap: 10 }}>\n        {ad.logo && (\n          <img src={ad.logo} alt=\"\" style={{ width: 38, height: 38, borderRadius: '50%', objectFit: 'cover', flexShrink: 0 }} />\n        )}\n        <div style={{ minWidth: 0 }}>\n          <div style={{ fontWeight: 700, fontSize: 14, fontFamily: 'Poppins' }}>{ad.sponsor || 'Annonce'}</div>\n          <div style={{ fontSize: 11, color: '#8a8a8a' }}>Annonce \u00b7 Sponsoris\u00e9</div>\n        </div>\n      </div>\n\n      {ad.text && (\n        <div style={{ padding: '10px 16px 12px', fontSize: 14, lineHeight: 1.45, whiteSpace: 'pre-wrap' }}>{ad.text}</div>\n      )}\n\n      {ad.mediaURL && (ad.mediaType === 'video' ? (\n        <video\n          src={ad.mediaURL}\n          poster={ad.thumbURL || undefined}\n          controls\n          playsInline\n          onClick={open}\n          style={{ width: '100%', maxHeight: 520, objectFit: 'cover', display: 'block', background: '#000', cursor: 'pointer' }}\n        />\n      ) : (\n        <img\n          src={ad.mediaURL}\n          alt=\"\"\n          onClick={open}\n          style={{ width: '100%', maxHeight: 520, objectFit: 'cover', display: 'block', cursor: 'pointer' }}\n        />\n      ))}\n\n      <div style={{ padding: '12px 16px' }}>\n        <button\n          onClick={open}\n          style={{\n            width: '100%', padding: '11px 0', border: 'none', borderRadius: 12, cursor: 'pointer',\n            fontWeight: 700, fontSize: 14, fontFamily: 'Poppins', color: '#fff',\n            background: 'linear-gradient(135deg,#7c3aed,#a855f7)',\n          }}\n        >\n          {ad.cta || 'En savoir plus'}\n        </button>\n      </div>\n    </div>\n  );\n}\n";

const SPLASH = {"android/app/src/main/res/drawable-land-xxxhdpi/splash.png": "", "android/app/src/main/res/drawable-port-xhdpi/splash.png": "", "android/app/src/main/res/drawable-port-xxxhdpi/splash.png": "", "android/app/src/main/res/drawable-port-xxhdpi/splash.png": "", "android/app/src/main/res/drawable-land-hdpi/splash.png": "", "android/app/src/main/res/drawable-land-xhdpi/splash.png": "", "android/app/src/main/res/drawable-land-mdpi/splash.png": "", "android/app/src/main/res/drawable-land-xxhdpi/splash.png": "", "android/app/src/main/res/drawable-port-hdpi/splash.png": "", "android/app/src/main/res/drawable/splash.png": "", "android/app/src/main/res/drawable-port-mdpi/splash.png": ""};

/* ============================================================================
 *  patch-uifix-all.cjs  —  Trengo/Tsengo
 *  Correction de 4 problèmes, en un seul script idempotent :
 *    1. PWA install perdue  → ajoute un handler `fetch` au service worker
 *    2. Pub AdMob qui cache la navbar → retire le banner bas ; pub en in-feed
 *    3. Annonces sous forme de PUBLICATION (photo/vidéo) toutes les 4 posts
 *    4. Splash "X bleu" inconnu → logo Trengo ; status bar blanche
 *
 *  Usage (Termux) :
 *    cp /sdcard/Download/patch-uifix-all.cjs ~/Tsengo-fresh/
 *    cd ~/Tsengo-fresh && node patch-uifix-all.cjs
 *  Puis (web)    : npx vite build && git push
 *       (natif)  : npx cap sync android  +  rebuild APK (splash + status bar)
 * ==========================================================================*/
const fs = require('fs');
const path = require('path');

let OK = 0, SKIP = 0, FAIL = 0;
const ok   = (m) => { OK++;   console.log('✅ ' + m); };
const skip = (m) => { SKIP++; console.log('⏭️  ' + m + ' (déjà fait)'); };
const fail = (m) => { FAIL++; console.log('❌ ' + m); };

function read(p)  { return fs.readFileSync(p, 'utf8'); }
function write(p, s) { fs.writeFileSync(p, s); }
function exists(p){ return fs.existsSync(p); }

/* ---------------------------------------------------------------------------
 * 1) SERVICE WORKER — handler fetch  (rend la PWA installable de nouveau)
 * ------------------------------------------------------------------------ */
(function patchServiceWorker() {
  const p = 'public/firebase-messaging-sw.js';
  try {
    if (!exists(p)) return fail('SW introuvable : ' + p);
    let src = read(p);
    if (src.includes('TRENGO_PWA_FETCH')) return skip('SW : handler fetch');
    const block = `

/* ── TRENGO_PWA_FETCH : nécessaire pour l'installabilité PWA + offline léger ──
 * Chrome n'affiche "Installer" que si le SW possède un handler 'fetch'.
 * On intercepte UNIQUEMENT les navigations (network-first, cache de secours).
 * Les assets (chunks JS hashés) passent au réseau → pas de chunk périmé. */
const TRENGO_CACHE = 'trengo-shell-v1';
self.addEventListener('install',  (e) => self.skipWaiting());
self.addEventListener('activate', (e) => e.waitUntil(self.clients.claim()));
self.addEventListener('fetch', (event) => {
  const req = event.request;
  if (req.method !== 'GET' || req.mode !== 'navigate') return;
  event.respondWith(
    fetch(req)
      .then((res) => { const c = res.clone(); caches.open(TRENGO_CACHE).then((k) => k.put('/', c)); return res; })
      .catch(() => caches.match('/'))
  );
});
`;
    write(p, src + block);
    ok('SW : handler fetch ajouté → PWA installable');
  } catch (e) { fail('SW : ' + e.message); }
})();

/* ---------------------------------------------------------------------------
 * 2) APP.JSX — retire le banner AdMob du bas (il cachait la navbar)
 * ------------------------------------------------------------------------ */
(function patchApp() {
  const p = 'src/App.jsx';
  try {
    if (!exists(p)) return fail('App.jsx introuvable');
    let src = read(p);
    if (!src.includes('.then(showBannerAd)')) return skip('App.jsx : banner AdMob');
    src = src.replace(
      'useEffect(() => { initAdMob().then(showBannerAd); }, []);',
      'useEffect(() => { initAdMob(); }, []); // banner bas retiré → pubs in-feed (SponsoredPost)'
    );
    write(p, src);
    ok('App.jsx : banner AdMob du bas retiré (navbar dégagée)');
  } catch (e) { fail('App.jsx : ' + e.message); }
})();

/* ---------------------------------------------------------------------------
 * 3a) Nouveau composant SponsoredPost.jsx  (annonce = publication)
 * ------------------------------------------------------------------------ */
(function createSponsoredPost() {
  const p = 'src/components/SponsoredPost.jsx';
  try {
    write(p, SPONSORED_POST_SRC);
    ok('SponsoredPost.jsx créé/mis à jour');
  } catch (e) { fail('SponsoredPost.jsx : ' + e.message); }
})();

/* ---------------------------------------------------------------------------
 * 3b) HOME.JSX — import + hook + injection dans le feed (toutes les 4 posts)
 * ------------------------------------------------------------------------ */
(function patchHome() {
  const p = 'src/pages/Home.jsx';
  try {
    if (!exists(p)) return fail('Home.jsx introuvable');
    let src = read(p);
    let changed = false;

    // import
    if (!src.includes("components/SponsoredPost")) {
      src = src.replace(
        "import StoryRing from '../components/StoryRing';",
        "import StoryRing from '../components/StoryRing';\nimport SponsoredPost, { useFeedAds } from '../components/SponsoredPost';"
      );
      changed = true;
    }

    // hook (dans le corps du composant, après l'état posts)
    if (!src.includes('useFeedAds(')) {
      src = src.replace(
        /(const \[posts, setPosts\]\s*=\s*useState\(\[\]\);)/,
        "$1\n  const feedAds = useFeedAds();"
      );
      changed = true;
    }

    // injection dans le map du feed (avant la carte du post)
    if (!src.includes('<SponsoredPost')) {
      const anchor = '<div className="card post-card animate-fade" style={{ marginBottom:14,';
      if (!src.includes(anchor)) throw new Error('ancre carte post introuvable');
      const inject =
        '{feedAds.length > 0 && pIdx > 0 && pIdx % 4 === 0 && (\n' +
        '            <SponsoredPost ad={feedAds[(Math.floor(pIdx / 4) - 1) % feedAds.length]} />\n' +
        '          )}\n          ';
      src = src.replace(anchor, inject + anchor);
      changed = true;
    }

    if (!changed) return skip('Home.jsx : annonces in-feed');
    write(p, src);
    ok('Home.jsx : annonces in-feed (1 pub / 4 posts)');
  } catch (e) { fail('Home.jsx : ' + e.message); }
})();

/* ---------------------------------------------------------------------------
 * 4a) STYLES.XML — status bar blanche + icônes sombres (Android)
 * ------------------------------------------------------------------------ */
(function patchStatusBar() {
  const p = 'android/app/src/main/res/values/styles.xml';
  try {
    if (!exists(p)) return fail('styles.xml introuvable');
    let src = read(p);
    if (src.includes('windowLightStatusBar')) return skip('styles.xml : status bar');
    const items =
      '\n        <item name="android:statusBarColor">#FFFFFF</item>' +
      '\n        <item name="android:windowLightStatusBar">true</item>';
    // thème d'exécution (launch) + thème NoActionBar
    src = src.replace('<item name="android:background">@drawable/splash</item>',
                      '<item name="android:background">@drawable/splash</item>' + items);
    src = src.replace('<item name="android:background">@null</item>',
                      '<item name="android:background">@null</item>' + items);
    write(p, src);
    ok('styles.xml : status bar blanche + icônes sombres');
  } catch (e) { fail('styles.xml : ' + e.message); }
})();

/* ---------------------------------------------------------------------------
 * 4b) SPLASH — remplace le "X bleu" par le logo Trengo (11 densités)
 * ------------------------------------------------------------------------ */
(function patchSplash() {
  try {
    let n = 0;
    for (const rel of Object.keys(SPLASH)) {
      if (!exists(path.dirname(rel))) continue;
      write(rel, Buffer.from(SPLASH[rel], 'base64'));
      n++;
    }
    if (n === 0) fail('splash : aucun dossier drawable trouvé');
    else ok('splash : logo Trengo écrit sur ' + n + ' densités');
  } catch (e) { fail('splash : ' + e.message); }
})();

